//! OCR / document-understanding admission probe for GLM-OCR.
//!
//! End-to-end image→text gate for the gnosis distributed-inference runtime.
//! Mirrors `vl-probe` but swaps in the GLM-OCR vision tower
//! (`model_glm_ocr_vit`) and applies a TEXT-OVERLAP gate suited to OCR: the
//! decoded output must contain (most of) the words known to be in the test
//! image. Looser than exact-match -- robust to punctuation / casing / a missed
//! token -- but far stricter than vl-probe's "on-topic keyword" caption gate.
//!
//!   1. Load the dense `.knot` (GLM-4 text backbone + GLM-OCR vision tower,
//!      encoded by encode-knot.py's glm_ocr branch, arch stamped "qwen2" so
//!      NativeLlama drives the sandwich-normed text backbone).
//!   2. Read preprocessed image patches (`preprocess-vl-image.py` -- GLM-OCR
//!      shares the Qwen2.5-VL CLIP normalization + patch/merge sizes).
//!   3. Run the GLM-OCR ViT → visual tokens [N, out_hidden].
//!   4. Embed the text prompt token IDs (`--text-tokens`, an OCR instruction
//!      such as "Read the text in this image.") → text embeddings.
//!   5. Splice [visual ; text] into the residual stream, chunked prefill.
//!   6. Greedy-decode up to `--max-new` tokens.
//!   7. Detokenize via the knot's GGUF tokenizer (`--tokenizer`) and gate:
//!        PASS iff the decoded text contains >= `--min-overlap` fraction of the
//!        `--expect` words (whitespace-split, case-insensitive, alnum-stripped).
//!
//! Usage
//! -----
//! ```
//! ocr-probe \
//!   --knot        /workspace/glm-ocr.knot \
//!   --pixels      /tmp/ocr_hello_patches.bin \
//!   --text-tokens <prompt CSV> \
//!   --tokenizer   /workspace/glm-ocr.gguf \
//!   --expect      "HELLO WORLD 2026" \
//!   --min-overlap 0.66 \
//!   --max-new     48
//! ```

use std::path::PathBuf;
use std::sync::Arc;
use std::time::Instant;

use distributed_inference::loader::KnotWeights;
use distributed_inference::model::NativeLlamaPipeline;
use distributed_inference::model_glm_ocr_vit::{GlmOcrViT, GlmOcrVitConfig};

fn die(msg: impl AsRef<str>) -> ! {
    eprintln!("ocr-probe: {}", msg.as_ref());
    std::process::exit(2);
}

struct Args {
    knot: String,
    pixels: PathBuf,
    text_tokens: Vec<u32>,
    tokenizer: Option<PathBuf>,
    expect: String,
    min_overlap: f32,
    max_new: usize,
}

fn parse_args() -> Args {
    let mut knot: Option<String> = None;
    let mut pixels: Option<PathBuf> = None;
    let mut text_tokens: Vec<u32> = Vec::new();
    let mut tokenizer: Option<PathBuf> = None;
    let mut expect = String::new();
    let mut min_overlap = 0.66f32;
    let mut max_new = 48usize;

    let raw: Vec<String> = std::env::args().skip(1).collect();
    let mut i = 0;
    while i < raw.len() {
        match raw[i].as_str() {
            "--knot" => {
                i += 1;
                knot = Some(
                    raw.get(i)
                        .unwrap_or_else(|| die("--knot needs a path"))
                        .clone(),
                );
            }
            "--pixels" => {
                i += 1;
                pixels = Some(PathBuf::from(
                    raw.get(i).unwrap_or_else(|| die("--pixels needs a path")),
                ));
            }
            "--text-tokens" => {
                i += 1;
                let s = raw
                    .get(i)
                    .unwrap_or_else(|| die("--text-tokens needs a CSV"));
                text_tokens = s
                    .split(',')
                    .map(|t| t.trim())
                    .filter(|t| !t.is_empty())
                    .map(|t| {
                        t.parse::<u32>()
                            .unwrap_or_else(|e| die(format!("text-tokens parse {t:?}: {e}")))
                    })
                    .collect();
            }
            "--tokenizer" => {
                i += 1;
                tokenizer = Some(PathBuf::from(
                    raw.get(i)
                        .unwrap_or_else(|| die("--tokenizer needs a path")),
                ));
            }
            "--expect" => {
                i += 1;
                expect = raw
                    .get(i)
                    .unwrap_or_else(|| die("--expect needs a string"))
                    .clone();
            }
            "--min-overlap" => {
                i += 1;
                min_overlap = raw
                    .get(i)
                    .unwrap_or_else(|| die("--min-overlap needs a float"))
                    .parse()
                    .unwrap_or_else(|e| die(format!("--min-overlap parse: {e}")));
            }
            "--max-new" => {
                i += 1;
                max_new = raw
                    .get(i)
                    .unwrap_or_else(|| die("--max-new needs an int"))
                    .parse()
                    .unwrap_or_else(|e| die(format!("--max-new parse: {e}")));
            }
            "-h" | "--help" => {
                eprintln!(
                    "usage: ocr-probe --knot <path> --pixels <bin> --text-tokens <csv> \
                     --expect <text> [--tokenizer <gguf>] [--min-overlap <f>] [--max-new <n>]"
                );
                std::process::exit(0);
            }
            other => die(format!("unknown arg: {other}")),
        }
        i += 1;
    }

    Args {
        knot: knot.unwrap_or_else(|| die("--knot required")),
        pixels: pixels.unwrap_or_else(|| die("--pixels required")),
        text_tokens: if text_tokens.is_empty() {
            die("--text-tokens required (pre-tokenized prompt CSV)")
        } else {
            text_tokens
        },
        tokenizer,
        expect: if expect.is_empty() {
            die("--expect required (the known text in the image)")
        } else {
            expect
        },
        min_overlap,
        max_new,
    }
}

/// Read the preprocessed patch grid written by preprocess-vl-image.py:
///   [u32 grid_h][u32 grid_w][u32 patch_dim]  then  f32[grid_h*grid_w*patch_dim]
fn read_pixels(path: &PathBuf) -> (usize, usize, usize, Vec<f32>) {
    let bytes = std::fs::read(path).unwrap_or_else(|e| die(format!("read pixels {path:?}: {e}")));
    if bytes.len() < 12 {
        die("pixels file too short (need 12-byte header)");
    }
    let grid_h = u32::from_le_bytes(bytes[0..4].try_into().unwrap()) as usize;
    let grid_w = u32::from_le_bytes(bytes[4..8].try_into().unwrap()) as usize;
    let patch_dim = u32::from_le_bytes(bytes[8..12].try_into().unwrap()) as usize;
    let n = grid_h * grid_w;
    let expected = n * patch_dim;
    let f = &bytes[12..];
    if f.len() != expected * 4 {
        die(format!(
            "pixels payload {} f32 != grid {grid_h}x{grid_w} * patch_dim {patch_dim} = {expected}",
            f.len() / 4
        ));
    }
    let pix: Vec<f32> = f
        .chunks_exact(4)
        .map(|c| f32::from_le_bytes([c[0], c[1], c[2], c[3]]))
        .collect();
    (grid_h, grid_w, patch_dim, pix)
}

/// GPT-2 byte-level token → text decode (same inversion vl-probe uses). The
/// GGUF stores tokens in the GPT-2 byte encoding; we invert it so the gate sees
/// real ASCII words. Good enough for the overlap gate; not a full BPE round-trip.
fn gpt2_byte_decode(tokens: &[String], ids: &[u32]) -> String {
    let mut byte_decoder = std::collections::HashMap::new();
    let mut printable: Vec<u32> = Vec::new();
    for r in (b'!' as u32)..=(b'~' as u32) {
        printable.push(r);
    }
    for r in 0xA1u32..=0xAC {
        printable.push(r);
    }
    for r in 0xAEu32..=0xFF {
        printable.push(r);
    }
    let mut extra = 0u32;
    let mut mapping: Vec<(u32, char)> = Vec::new();
    for b in 0u32..256 {
        if printable.contains(&b) {
            mapping.push((b, char::from_u32(b).unwrap()));
        } else {
            let c = char::from_u32(256 + extra).unwrap();
            mapping.push((b, c));
            extra += 1;
        }
    }
    for (b, c) in mapping {
        byte_decoder.insert(c, b as u8);
    }

    let mut out_bytes: Vec<u8> = Vec::new();
    for &id in ids {
        let Some(tok) = tokens.get(id as usize) else {
            continue;
        };
        for ch in tok.chars() {
            if let Some(&b) = byte_decoder.get(&ch) {
                out_bytes.push(b);
            } else {
                let mut buf = [0u8; 4];
                out_bytes.extend_from_slice(ch.encode_utf8(&mut buf).as_bytes());
            }
        }
    }
    String::from_utf8_lossy(&out_bytes).into_owned()
}

/// Walk a GGUF and return `tokenizer.ggml.tokens` (pure byte-walk, no extra crate).
fn read_gguf_tokens(path: &std::path::Path) -> Result<Vec<String>, String> {
    use std::io::{Read, Seek, SeekFrom};
    const GGUF_MAGIC: u32 = 0x4655_4747;
    const T_STRING: u32 = 8;
    const T_ARRAY: u32 = 9;
    let mut f = std::fs::File::open(path).map_err(|e| format!("open gguf: {e}"))?;
    fn rd_u32(f: &mut std::fs::File) -> Result<u32, String> {
        let mut b = [0u8; 4];
        f.read_exact(&mut b).map_err(|e| e.to_string())?;
        Ok(u32::from_le_bytes(b))
    }
    fn rd_u64(f: &mut std::fs::File) -> Result<u64, String> {
        let mut b = [0u8; 8];
        f.read_exact(&mut b).map_err(|e| e.to_string())?;
        Ok(u64::from_le_bytes(b))
    }
    fn rd_string(f: &mut std::fs::File) -> Result<String, String> {
        let len = rd_u64(f)? as usize;
        let mut buf = vec![0u8; len];
        f.read_exact(&mut buf).map_err(|e| e.to_string())?;
        Ok(String::from_utf8_lossy(&buf).into_owned())
    }
    fn scalar_size(t: u32) -> Result<u64, String> {
        Ok(match t {
            0 | 1 | 7 => 1,
            2 | 3 => 2,
            4..=6 => 4,
            10..=12 => 8,
            other => return Err(format!("unsupported gguf scalar type {other}")),
        })
    }
    fn skip_value(f: &mut std::fs::File, t: u32) -> Result<(), String> {
        match t {
            T_STRING => {
                let len = rd_u64(f)?;
                f.seek(SeekFrom::Current(len as i64))
                    .map_err(|e| e.to_string())?;
            }
            T_ARRAY => {
                let at = rd_u32(f)?;
                let al = rd_u64(f)?;
                if at == T_STRING {
                    for _ in 0..al {
                        let len = rd_u64(f)?;
                        f.seek(SeekFrom::Current(len as i64))
                            .map_err(|e| e.to_string())?;
                    }
                } else {
                    let sz = scalar_size(at)?;
                    f.seek(SeekFrom::Current((sz * al) as i64))
                        .map_err(|e| e.to_string())?;
                }
            }
            scalar => {
                let sz = scalar_size(scalar)?;
                f.seek(SeekFrom::Current(sz as i64))
                    .map_err(|e| e.to_string())?;
            }
        }
        Ok(())
    }
    if rd_u32(&mut f)? != GGUF_MAGIC {
        return Err("not a GGUF file (bad magic)".to_string());
    }
    let version = rd_u32(&mut f)?;
    if version < 2 {
        return Err(format!("unsupported GGUF version {version}"));
    }
    let _n_tensors = rd_u64(&mut f)?;
    let n_kv = rd_u64(&mut f)?;
    for _ in 0..n_kv {
        let key = rd_string(&mut f)?;
        let vtype = rd_u32(&mut f)?;
        if key == "tokenizer.ggml.tokens" {
            if vtype != T_ARRAY {
                return Err("tokenizer.ggml.tokens is not an array".to_string());
            }
            let at = rd_u32(&mut f)?;
            if at != T_STRING {
                return Err("tokenizer.ggml.tokens is not a string array".to_string());
            }
            let al = rd_u64(&mut f)? as usize;
            let mut tokens = Vec::with_capacity(al);
            for _ in 0..al {
                tokens.push(rd_string(&mut f)?);
            }
            return Ok(tokens);
        }
        skip_value(&mut f, vtype)?;
    }
    Err("GGUF metadata has no tokenizer.ggml.tokens".to_string())
}

/// Normalize a string to lowercase alphanumeric whitespace-separated words.
fn words(s: &str) -> Vec<String> {
    s.split_whitespace()
        .map(|w| {
            w.chars()
                .filter(|c| c.is_alphanumeric())
                .flat_map(|c| c.to_lowercase())
                .collect::<String>()
        })
        .filter(|w| !w.is_empty())
        .collect()
}

fn main() {
    let args = parse_args();
    let t_all = Instant::now();
    eprintln!(
        "ocr-probe: knot={} pixels={:?} text_tokens={} expect={:?} min_overlap={} max_new={}",
        args.knot,
        args.pixels,
        args.text_tokens.len(),
        args.expect,
        args.min_overlap,
        args.max_new
    );

    // 1. Load the dense knot.
    let t_load = Instant::now();
    let knot = KnotWeights::load(&args.knot).unwrap_or_else(|e| die(format!("knot load: {e}")));
    let cfg = knot
        .config
        .clone()
        .unwrap_or_else(|| die("knot has no config block"));
    eprintln!(
        "  loaded knot in {:.2}s  hidden={} layers={} heads={} kv={} head_dim={} vocab={} arch={}",
        t_load.elapsed().as_secs_f32(),
        cfg.hidden_dim,
        cfg.num_layers,
        cfg.num_heads,
        cfg.num_kv_heads,
        cfg.head_dim,
        cfg.vocab_size,
        cfg.arch,
    );
    let hidden_dim = cfg.hidden_dim;
    let num_layers = cfg.num_layers;
    let vocab_size = cfg.vocab_size;

    // 2. Read preprocessed image patches.
    let (grid_h, grid_w, _patch_dim, pixels) = read_pixels(&args.pixels);
    eprintln!(
        "  pixels: grid {grid_h}x{grid_w}  ({} patches)",
        grid_h * grid_w
    );

    // 3. Run the GLM-OCR ViT → visual tokens [n_merged, out_hidden].
    let vit_cfg = GlmOcrVitConfig::default();
    if vit_cfg.out_hidden_size != hidden_dim {
        eprintln!(
            "  WARNING: ViT out_hidden {} != text hidden {hidden_dim}; using text hidden \
             via config defaults assumes GLM-OCR (1536). Check the knot's vit_out_hidden_size.",
            vit_cfg.out_hidden_size
        );
    }
    let backend = Arc::clone(&knot.backend);
    if !backend.has_tensor("vit_patch_embed_weight") {
        die(
            "knot has no vit_patch_embed_weight — vision tower was NOT encoded. \
             Re-encode with the glm_ocr branch of encode-knot.py.",
        );
    }
    let vit = GlmOcrViT::new(vit_cfg, backend);
    let t_vit = Instant::now();
    let visual = vit
        .forward(&pixels, grid_h, grid_w)
        .unwrap_or_else(|e| die(format!("ViT forward: {e}")));
    let n_visual = visual.len() / hidden_dim;
    {
        let nan = visual.iter().filter(|x| x.is_nan()).count();
        let max = visual.iter().fold(0.0f32, |a, &b| a.max(b.abs()));
        eprintln!(
            "  ViT forward: {:.2}s  visual_tokens={n_visual}x{hidden_dim}  |v|max={max:.3} nan={nan}",
            t_vit.elapsed().as_secs_f32()
        );
        if nan > 0 {
            println!("\nFAIL: ViT produced {nan} NaN values");
            std::process::exit(1);
        }
    }

    // 4. Build the pipeline + embed the text prompt.
    let mut pipeline = NativeLlamaPipeline::from_knot(knot, false, 0.0);
    let t_embed = Instant::now();
    let text_emb = pipeline
        .embed_chunk(&args.text_tokens, 0)
        .unwrap_or_else(|e| die(format!("embed_chunk: {e}")));
    let n_text = args.text_tokens.len();
    eprintln!(
        "  embed text: {:.2}s  {n_text} tokens",
        t_embed.elapsed().as_secs_f32()
    );

    // 5. GLM-OCR frames the image as <|begin_of_image|> <|image|>*N <|end_of_image|>
    //    INSIDE the user turn; the N <|image|>(59280) placeholder embeddings must be
    //    OVERWRITTEN by the ViT tokens (not bare-prepended, which leaves the image
    //    outside the prompt and the model emits <|user|> and reads nothing). So the
    //    residual is the full chat-templated prompt with the visual tokens spliced
    //    in at the placeholder offset.
    const GLM_IMAGE_PAD: u32 = 59280; // <|image|>
    let seq_len = n_text;
    let mut residual = text_emb; // [n_text, hidden], placeholders embedded
    let img_start = args
        .text_tokens
        .iter()
        .position(|&t| t == GLM_IMAGE_PAD)
        .unwrap_or_else(|| die("--text-tokens has no <|image|>(59280) placeholder span"));
    let n_pad = args
        .text_tokens
        .iter()
        .filter(|&&t| t == GLM_IMAGE_PAD)
        .count();
    if n_pad != n_visual {
        die(format!(
            "image-pad count {n_pad} (in --text-tokens) != n_visual {n_visual} (from ViT)"
        ));
    }
    residual[img_start * hidden_dim..(img_start + n_visual) * hidden_dim].copy_from_slice(&visual);
    eprintln!(
        "  prefill seq_len={seq_len} (visual span @ {img_start}..{} of {n_text} prompt tokens)",
        img_start + n_visual
    );

    const PREFILL_CHUNK: usize = 8;
    let t_prefill = Instant::now();
    let mut last_chunk_out: Vec<f32> = Vec::new();
    let mut last_chunk_len = 0usize;
    let mut chunk_start = 0usize;
    while chunk_start < seq_len {
        let chunk_len = (seq_len - chunk_start).min(PREFILL_CHUNK);
        let chunk_in = &residual[chunk_start * hidden_dim..(chunk_start + chunk_len) * hidden_dim];
        for layer in 0..num_layers {
            let is_first = layer == 0;
            let is_last = layer == num_layers - 1;
            let attn_in: &[f32] = if is_first { chunk_in } else { &[] };
            pipeline
                .forward_range_attn_chunk(attn_in, layer, chunk_start, chunk_len, is_first)
                .unwrap_or_else(|e| die(format!("attn L{layer}: {e}")));
            pipeline
                .forward_range_ffn_gate_chunk(layer, chunk_len)
                .unwrap_or_else(|e| die(format!("ffn_gate L{layer}: {e}")));
            pipeline
                .forward_range_ffn_up_chunk(layer, chunk_len)
                .unwrap_or_else(|e| die(format!("ffn_up L{layer}: {e}")));
            let out = pipeline
                .forward_range_ffn_down_chunk(layer, chunk_len, is_last)
                .unwrap_or_else(|e| die(format!("ffn_down L{layer}: {e}")));
            if is_last {
                last_chunk_out = out;
                last_chunk_len = chunk_len;
            }
        }
        chunk_start += chunk_len;
    }
    eprintln!(
        "  prefill {num_layers} layers: {:.2}s",
        t_prefill.elapsed().as_secs_f32()
    );

    let logits = pipeline
        .lm_head_only(&last_chunk_out, last_chunk_len)
        .unwrap_or_else(|e| die(format!("lm_head_only: {e}")));
    let nan = logits.iter().filter(|x| x.is_nan()).count();
    if nan > 0 {
        println!("\nFAIL: {nan}/{vocab_size} prefill logits are NaN (broken text backbone)");
        std::process::exit(1);
    }
    let first_tok = argmax(&logits) as u32;

    // 6. Greedy decode. GLM-OCR EOS ids: 59246 (pad/eos) and 59253.
    let t_dec = Instant::now();
    let mut generated: Vec<u32> = vec![first_tok];
    let mut cur = first_tok;
    let mut pos = seq_len;
    let stop = |t: u32| t == 59246 || t == 59253;
    for _ in 1..args.max_new {
        if stop(cur) {
            break;
        }
        let (next, _, _) = pipeline
            .decode_next_fast_argmax(cur, pos)
            .unwrap_or_else(|e| die(format!("decode at pos {pos}: {e}")));
        pos += 1;
        generated.push(next);
        cur = next;
    }
    eprintln!(
        "  decode {} tokens: {:.2}s",
        generated.len(),
        t_dec.elapsed().as_secs_f32()
    );

    // 7. Detokenize + overlap gate.
    let text = match args.tokenizer.as_ref() {
        Some(p) => match read_gguf_tokens(p) {
            Ok(tokens) => gpt2_byte_decode(&tokens, &generated),
            Err(e) => {
                eprintln!("  WARNING: tokenizer load failed ({e}); gating on token IDs only");
                String::new()
            }
        },
        None => {
            eprintln!("  no --tokenizer; cannot run text-overlap gate");
            String::new()
        }
    };

    println!("\n── ocr-probe decoded ({} tokens) ──", generated.len());
    println!("  ids:  {generated:?}");
    if !text.is_empty() {
        println!("  text: {text:?}");
    }

    // Degeneracy guard: distinct non-stop token ids.
    let distinct: std::collections::HashSet<u32> =
        generated.iter().copied().filter(|t| !stop(*t)).collect();
    let non_degenerate = distinct.len() >= 2 && !generated.is_empty();

    // Word-overlap: fraction of expected words present in the decoded text.
    let expect_words = words(&args.expect);
    let decoded_words: std::collections::HashSet<String> = words(&text).into_iter().collect();
    let mut matched = 0usize;
    let mut hits: Vec<String> = Vec::new();
    let mut misses: Vec<String> = Vec::new();
    for w in &expect_words {
        if decoded_words.contains(w) {
            matched += 1;
            hits.push(w.clone());
        } else {
            misses.push(w.clone());
        }
    }
    let overlap = if expect_words.is_empty() {
        0.0
    } else {
        matched as f32 / expect_words.len() as f32
    };

    println!("\n── ocr-probe gate (text-overlap gate) ──");
    println!("  expected words:   {expect_words:?}");
    println!("  matched:          {hits:?}");
    println!("  missed:           {misses:?}");
    println!(
        "  overlap:          {matched}/{} = {overlap:.2}  (need >= {:.2})",
        expect_words.len(),
        args.min_overlap
    );
    println!("  non-degenerate:   {non_degenerate}");
    eprintln!("  total wall: {:.2}s", t_all.elapsed().as_secs_f32());

    let pass = non_degenerate && !text.is_empty() && overlap >= args.min_overlap;
    if pass {
        println!("\nPASS: decoded text overlaps the known image text (overlap {overlap:.2})");
        std::process::exit(0);
    } else {
        println!(
            "\nFAIL: insufficient overlap (overlap={overlap:.2} non_degenerate={non_degenerate} \
             text_empty={})",
            text.is_empty()
        );
        std::process::exit(1);
    }
}

fn argmax(v: &[f32]) -> usize {
    v.iter()
        .enumerate()
        .fold((0usize, f32::NEG_INFINITY), |(bi, bv), (i, &x)| {
            if x > bv {
                (i, x)
            } else {
                (bi, bv)
            }
        })
        .0
}
